// ─── Helper functions ──────────────────────────────────────────────────

export function getTeamBySlug(slug: string): TeamData | undefined {
  return TEAMS_DATA.find(t => t.slug === slug);
}

export function getTeamsByGroup(group: string): TeamData[] {
  return TEAMS_DATA.filter(t => t.group === group);
}

export function getTeamsByConfederation(conf: string): TeamData[] {
  return TEAMS_DATA.filter(t => t.confederation === conf);
}

export function getSquadByPosition(team: TeamData, pos: Position): Player[] {
  return team.players.filter(p => p.pos === pos);
}
